import React, { useState } from 'react';
import { Button, Text, TextInput } from 'react-native';
import { Constants } from 'expo-constants';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';

const OAuthScreen = () => {
  const [code, setCode] = useState('');
  const [token, setToken] = useState('');

  const exchangeCodeForToken = async () => {
    try {
      const response = await fetch('YOUR_AUTHORIZATION_ENDPOINT', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          client_id: clientId,
          client_secret: clientSecret,
          code: code,
        }),
      });

      const data = await response.json();
      setToken(data.access_token);
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <React.View>
      <Text>Enter the authorization code:</Text>
      <TextInput onChangeText={setCode} value={code} />
      <Button title="Exchange Code for Token" onPress={exchangeCodeForToken} />
      <Text>Token: {token}</Text>
    </React.View>
  );
};

export default OAuthScreen;